// State -> populate Districts
document.getElementById("state").addEventListener("change", function() {
  const state = this.value;
  const districtEl = document.getElementById("district");
  const seasonEl   = document.getElementById("season");
  const cropEl     = document.getElementById("crop");

  districtEl.innerHTML = '<option value="">Select a district</option>';
  seasonEl.value = "";
  cropEl.innerHTML = '<option value="">Select crop</option>';

  if (state && cropMapping[state]) {
    Object.keys(cropMapping[state]).sort().forEach(function(d) {
      const opt = document.createElement("option");
      opt.value = d;
      opt.text  = d.charAt(0) + d.slice(1).toLowerCase().replace(/_/g, " ");
      districtEl.appendChild(opt);
    });
  }
});

// District + Season -> populate Crops
function updateCrops() {
  const state    = document.getElementById("state").value;
  const district = document.getElementById("district").value;
  const season   = document.getElementById("season").value;
  
  // FIXED: No more .value causing the crash!
  const cropEl   = document.getElementById("crop");

  cropEl.innerHTML = '<option value="">Select crop</option>';

  if (state && district && season &&
      cropMapping[state] &&
      cropMapping[state][district] &&
      cropMapping[state][district][season]) {
    cropMapping[state][district][season].forEach(function(c) {
      const opt = document.createElement("option");
      opt.value = c;
      opt.text  = c;
      cropEl.appendChild(opt);
    });
  }
}

document.getElementById("district").addEventListener("change", updateCrops);
document.getElementById("season").addEventListener("change",  updateCrops);
</script>

